import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
import { createWindowCloseArbiter, WINDOW_CLOSE_GRACE_PERIOD_MS, } from "./studioTeardown.js";
const closed = (id = "original") => ({
    id,
    type: "studio:window-closed",
    data: {},
});
const started = () => ({
    id: "reload",
    type: "studio:session-started",
    data: {},
});
describe("createWindowCloseArbiter", () => {
    let onConfirmed;
    let onRefuted;
    beforeEach(() => {
        vi.useFakeTimers();
        onConfirmed = vi.fn();
        onRefuted = vi.fn();
    });
    afterEach(() => {
        vi.useRealTimers();
    });
    it("confirms with the original event after the grace period passes untouched", () => {
        const arbiter = createWindowCloseArbiter({ onConfirmed, onRefuted });
        arbiter.handleEvent(closed());
        vi.advanceTimersByTime(WINDOW_CLOSE_GRACE_PERIOD_MS - 1);
        expect(onConfirmed).not.toHaveBeenCalled();
        expect(arbiter.hasPendingCandidate()).toBe(true);
        vi.advanceTimersByTime(2);
        expect(onConfirmed).toHaveBeenCalledTimes(1);
        expect(onConfirmed.mock.calls[0][0].id).toBe("original");
        expect(arbiter.hasPendingCandidate()).toBe(false);
    });
    it("refutes a pending candidate on session-started (page refresh)", () => {
        const arbiter = createWindowCloseArbiter({ onConfirmed, onRefuted });
        arbiter.handleEvent(closed());
        arbiter.handleEvent(started());
        vi.advanceTimersByTime(WINDOW_CLOSE_GRACE_PERIOD_MS * 2);
        expect(onConfirmed).not.toHaveBeenCalled();
        expect(onRefuted).toHaveBeenCalledTimes(1);
    });
    it("ignores session-started with no pending candidate", () => {
        const arbiter = createWindowCloseArbiter({ onConfirmed, onRefuted });
        arbiter.handleEvent(started());
        expect(onRefuted).not.toHaveBeenCalled();
    });
    it("a newer window-closed restarts the grace", () => {
        const arbiter = createWindowCloseArbiter({ onConfirmed, onRefuted });
        arbiter.handleEvent(closed());
        vi.advanceTimersByTime(WINDOW_CLOSE_GRACE_PERIOD_MS - 1);
        arbiter.handleEvent(closed());
        // The first candidate's expiry passes without confirming.
        vi.advanceTimersByTime(2);
        expect(onConfirmed).not.toHaveBeenCalled();
        vi.advanceTimersByTime(WINDOW_CLOSE_GRACE_PERIOD_MS);
        expect(onConfirmed).toHaveBeenCalledTimes(1);
    });
    it("cancel drops a pending candidate without confirming or refuting", () => {
        const arbiter = createWindowCloseArbiter({ onConfirmed, onRefuted });
        arbiter.handleEvent(closed());
        arbiter.cancel();
        vi.advanceTimersByTime(WINDOW_CLOSE_GRACE_PERIOD_MS * 2);
        expect(onConfirmed).not.toHaveBeenCalled();
        expect(onRefuted).not.toHaveBeenCalled();
        expect(arbiter.hasPendingCandidate()).toBe(false);
    });
    it("a fresh candidate after a refutation still confirms", () => {
        const arbiter = createWindowCloseArbiter({ onConfirmed, onRefuted });
        arbiter.handleEvent(closed());
        arbiter.handleEvent(started());
        arbiter.handleEvent(closed());
        vi.advanceTimersByTime(WINDOW_CLOSE_GRACE_PERIOD_MS + 1);
        expect(onRefuted).toHaveBeenCalledTimes(1);
        expect(onConfirmed).toHaveBeenCalledTimes(1);
    });
});
